#include <FastLED.h>
#include <ArduinoJson.h>

#if defined(ESP32)
#include <WiFi.h>
#include <WebServer.h>
#endif

// LED Strip Configuration
#define LED_PIN {{.ledPin}}
#define NUM_LEDS {{.numLeds}}
#define BRIGHTNESS {{.brightness}}
#define COLOR_ORDER "{{.colorOrder}}"
#define ANIMATION_SPEED {{.animationSpeed}}
#define ENABLE_WEB_CONTROL {{.enableWebControl}}

// WiFi Configuration (ESP32 only)
#if defined(ESP32)
const char* ssid = "{{.ssid}}";
const char* password = "{{.password}}";
const char* deviceName = "{{.deviceName}}";
WebServer server(80);
#endif

// Global variables
CRGB leds[NUM_LEDS];
String currentPattern = "rainbow";
uint8_t currentHue = 0;
uint8_t currentBrightness = BRIGHTNESS;
uint8_t currentSpeed = ANIMATION_SPEED;
unsigned long lastUpdateTime = 0;
bool animationRunning = true;

// Animation variables
uint8_t chasePosition = 0;
uint8_t fadePosition = 0;
uint8_t sparklePosition = 0;
uint8_t scannerPosition = 0;
bool scannerDirection = true;
uint8_t theaterChasePosition = 0;
uint8_t theaterChaseStep = 0;

// Function prototypes
void setupLEDs();
void updateAnimation();
void rainbow();
void chase(CRGB color);
void fade(CRGB color);
void sparkle(CRGB color);
void colorWipe(CRGB color);
void theaterChase(CRGB color);
void scanner(CRGB color);
void solidColor(CRGB color);
CRGB hexToCRGB(String hexColor);
#if defined(ESP32)
void setupWiFi();
void setupWebServer();
void handleRoot();
void handleControl();
void handleStatus();
void handlePatterns();
String getHTMLHeader();
String getHTMLFooter();
String getControlPanel();
String getPatternButtons();
String getJavaScript();
String getCSS();
#endif

void setup() {
  Serial.begin(115200);
  Serial.println("LED Strip Animation Controller Starting...");

  setupLEDs();

#if defined(ESP32)
  if (ENABLE_WEB_CONTROL) {
    setupWiFi();
    setupWebServer();
    Serial.print("Web server started! IP: ");
    Serial.println(WiFi.localIP());
  }
#endif

  Serial.print("LED Strip initialized - ");
  Serial.print(NUM_LEDS);
  Serial.print(" LEDs, Color Order: ");
  Serial.println(COLOR_ORDER);
  Serial.println("Setup completed!");
}

void setupLEDs() {
  // Set up FastLED based on color order
  #if defined(COLOR_ORDER_GRB)
    FastLED.addLeds<WS2812B, LED_PIN, COLOR_ORDER>(leds, NUM_LEDS);
  #elif defined(COLOR_ORDER_RGB)
    FastLED.addLeds<WS2812B, LED_PIN, RGB>(leds, NUM_LEDS);
  #elif defined(COLOR_ORDER_BRG)
    FastLED.addLeds<WS2812B, LED_PIN, BRG>(leds, NUM_LEDS);
  #else
    FastLED.addLeds<WS2812B, LED_PIN, GRB>(leds, NUM_LEDS);
  #endif

  FastLED.setBrightness(currentBrightness);
  FastLED.clear();
  FastLED.show();
}

#if defined(ESP32)
void setupWiFi() {
  Serial.println("Connecting to WiFi...");

  WiFi.begin(ssid, password);

  int attempts = 0;
  while (WiFi.status() != WL_CONNECTED && attempts < 20) {
    delay(500);
    Serial.print(".");
    attempts++;
  }

  if (WiFi.status() == WL_CONNECTED) {
    Serial.println("");
    Serial.println("WiFi connected!");
    Serial.print("IP address: ");
    Serial.println(WiFi.localIP());
  } else {
    Serial.println("Failed to connect to WiFi");
  }
}

void setupWebServer() {
  server.on("/", HTTP_GET, handleRoot);
  server.on("/control", HTTP_POST, handleControl);
  server.on("/status", HTTP_GET, handleStatus);
  server.on("/patterns", HTTP_GET, handlePatterns);

  server.on("/style.css", []() {
    server.send(200, "text/css", getCSS());
  });

  server.on("/script.js", []() {
    server.send(200, "application/javascript", getJavaScript());
  });

  server.begin();
}
#endif

void loop() {
#if defined(ESP32)
  if (ENABLE_WEB_CONTROL) {
    server.handleClient();
  }
#endif

  if (animationRunning) {
    updateAnimation();
  }

  delay(10);
}

void updateAnimation() {
  unsigned long currentTime = millis();
  unsigned long updateInterval = 1000 / currentSpeed;

  if (currentTime - lastUpdateTime >= updateInterval) {
    lastUpdateTime = currentTime;

    if (currentPattern == "rainbow") {
      rainbow();
    } else if (currentPattern == "chase") {
      chase(CRGB::Blue); // Default blue for chase
    } else if (currentPattern == "fade") {
      fade(CRGB::Red); // Default red for fade
    } else if (currentPattern == "sparkle") {
      sparkle(CRGB::White); // Default white for sparkle
    } else if (currentPattern == "color_wipe") {
      colorWipe(CRGB::Green);
    } else if (currentPattern == "theater_chase") {
      theaterChase(CRGB::Purple);
    } else if (currentPattern == "scanner") {
      scanner(CRGB::Orange);
    } else if (currentPattern == "solid") {
      solidColor(CRGB::Yellow);
    }

    FastLED.show();
  }
}

void rainbow() {
  fill_rainbow(leds, NUM_LEDS, currentHue++, 7);
}

void chase(CRGB color) {
  // Clear all LEDs
  fill_solid(leds, NUM_LEDS, CRGB::Black);

  // Set chase position
  leds[chasePosition] = color;

  // Move to next position
  chasePosition = (chasePosition + 1) % NUM_LEDS;
}

void fade(CRGB color) {
  // Calculate fade brightness
  uint8_t fadeBrightness = (sin8(fadePosition * 255 / NUM_LEDS) + 128) * currentBrightness / 255;

  // Fill all LEDs with fade effect
  fill_solid(leds, NUM_LEDS, color);
  FastLED.setBrightness(fadeBrightness);

  fadePosition = (fadePosition + 1) % NUM_LEDS;
}

void sparkle(CRGB color) {
  // Clear all LEDs
  fill_solid(leds, NUM_LEDS, CRGB::Black);

  // Add random sparkles
  for (int i = 0; i < NUM_LEDS / 10; i++) {
    if (random8() < 50) { // 20% chance to sparkle
      leds[random8(NUM_LEDS)] = color;
    }
  }
}

void colorWipe(CRGB color) {
  // Wipe color across the strip
  if (colorWipePosition < NUM_LEDS) {
    leds[colorWipePosition] = color;
    colorWipePosition++;
  } else {
    colorWipePosition = 0; // Reset for next wipe
  }
}

void theaterChase(CRGB color) {
  // Theater chase effect
  for (int i = 0; i < NUM_LEDS; i++) {
    if ((i + theaterChaseStep) % 3 == 0) {
      leds[i] = color;
    } else {
      leds[i] = CRGB::Black;
    }
  }

  theaterChaseStep = (theaterChaseStep + 1) % 3;
}

void scanner(CRGB color) {
  // Clear all LEDs
  fill_solid(leds, NUM_LEDS, CRGB::Black);

  // Create scanner effect
  for (int i = 0; i < 5; i++) {
    int pos = scannerPosition - i;
    if (pos >= 0 && pos < NUM_LEDS) {
      leds[pos] = color;
      leds[pos].fadeToBlackBy(64 * i);
    }

    pos = scannerPosition + i;
    if (pos >= 0 && pos < NUM_LEDS) {
      leds[pos] = color;
      leds[pos].fadeToBlackBy(64 * i);
    }
  }

  // Move scanner position
  if (scannerDirection) {
    scannerPosition++;
    if (scannerPosition >= NUM_LEDS + 5) {
      scannerPosition = NUM_LEDS + 4;
      scannerDirection = false;
    }
  } else {
    scannerPosition--;
    if (scannerPosition <= -5) {
      scannerPosition = -4;
      scannerDirection = true;
    }
  }
}

void solidColor(CRGB color) {
  fill_solid(leds, NUM_LEDS, color);
}

CRGB hexToCRGB(String hexColor) {
  // Remove # if present
  if (hexColor.startsWith("#")) {
    hexColor = hexColor.substring(1);
  }

  // Parse hex color
  long color = strtol(hexColor.c_str(), NULL, 16);

  return CRGB((color >> 16) & 0xFF, (color >> 8) & 0xFF, color & 0xFF);
}

#if defined(ESP32)
void handleRoot() {
  String html = getHTMLHeader();
  html += getControlPanel();
  html += getHTMLFooter();
  server.send(200, "text/html", html);
}

void handleControl() {
  String pattern = server.arg("pattern");
  String color = server.arg("color");
  String speed = server.arg("speed");
  String brightness = server.arg("brightness");

  bool changed = false;

  if (pattern.length() > 0) {
    currentPattern = pattern;
    changed = true;

    // Reset animation variables when pattern changes
    chasePosition = 0;
    fadePosition = 0;
    sparklePosition = 0;
    scannerPosition = 0;
    scannerDirection = true;
    colorWipePosition = 0;
    theaterChaseStep = 0;
    theaterChasePosition = 0;

    Serial.print("Pattern changed to: ");
    Serial.println(pattern);
  }

  if (speed.length() > 0) {
    int newSpeed = speed.toInt();
    if (newSpeed >= 1 && newSpeed <= 10) {
      currentSpeed = newSpeed;
      changed = true;
      Serial.print("Speed changed to: ");
      Serial.println(newSpeed);
    }
  }

  if (brightness.length() > 0) {
    int newBrightness = brightness.toInt();
    if (newBrightness >= 0 && newBrightness <= 255) {
      currentBrightness = newBrightness;
      FastLED.setBrightness(currentBrightness);
      changed = true;
      Serial.print("Brightness changed to: ");
      Serial.println(newBrightness);
    }
  }

  // Send JSON response
  StaticJsonDocument<200> doc;
  doc["success"] = true;
  doc["pattern"] = currentPattern;
  doc["speed"] = currentSpeed;
  doc["brightness"] = currentBrightness;
  doc["numLeds"] = NUM_LEDS;

  String response;
  serializeJson(doc, response);
  server.send(200, "application/json", response);
}

void handleStatus() {
  StaticJsonDocument<300> doc;
  doc["deviceName"] = deviceName;
  doc["pattern"] = currentPattern;
  doc["speed"] = currentSpeed;
  doc["brightness"] = currentBrightness;
  doc["numLeds"] = NUM_LEDS;
  doc["colorOrder"] = COLOR_ORDER;
  doc["uptime"] = millis();
  doc["animationRunning"] = animationRunning;

  // Add custom patterns
  JsonArray patterns = doc.createNestedArray("customPatterns");

  // Add built-in patterns
  JsonObject pattern1 = patterns.createNestedObject();
  pattern1["name"] = "Rainbow";
  pattern1["type"] = "rainbow";
  pattern1["speed"] = 5;
  patterns.add(pattern1);

  JsonObject pattern2 = patterns.createNestedObject();
  pattern2["name"] = "Chase";
  pattern2["type"] = "chase";
  pattern2["color"] = "#0000FF";
  pattern2["speed"] = 7;
  patterns.add(pattern2);

  JsonObject pattern3 = patterns.createNestedObject();
  pattern3["name"] = "Fade";
  pattern3["type"] = "fade";
  pattern3["color"] = "#FF0000";
  pattern3["speed"] = 3;
  patterns.add(pattern3);

  String response;
  serializeJson(doc, response);
  server.send(200, "application/json", response);
}

void handlePatterns() {
  StaticJsonDocument<200> doc;
  JsonArray patterns = doc.createNestedArray("patterns");

  // Add all available patterns
  JsonObject pattern1 = patterns.createNestedObject();
  pattern1["name"] = "Rainbow";
  pattern1["type"] = "rainbow";
  pattern1["description"] = "Rainbow color cycling effect";
  patterns.add(pattern1);

  JsonObject pattern2 = patterns.createNestedObject();
  pattern2["name"] = "Chase";
  pattern2["type"] = "chase";
  pattern2["description"] = "LED chase effect";
  pattern2["color"] = "#0000FF";
  patterns.add(pattern2);

  JsonObject pattern3 = patterns.createNestedObject();
  pattern3["name"] = "Fade";
  pattern3["type"] = "fade";
  pattern3["description"] = "Fade in/out effect";
  pattern3["color"] = "#FF0000";
  patterns.add(pattern3);

  JsonObject pattern4 = patterns.createNestedObject();
  pattern4["name"] = "Sparkle";
  pattern4["type"] = "sparkle";
  pattern4["description"] = "Random sparkle effect";
  pattern4["color"] = "#FFFFFF";
  patterns.add(pattern4);

  JsonObject pattern5 = patterns.createNestedObject();
  pattern5["name"] = "Color Wipe";
  pattern5["type"] = "color_wipe";
  pattern5["description"] = "Color wipe across strip";
  pattern5["color"] = "#00FF00";
  patterns.add(pattern5);

  JsonObject pattern6 = patterns.createNestedObject();
  pattern6[name"] = "Theater Chase";
  pattern6["type"] = "theater_chase";
  pattern6["description"] = "Theater chase effect";
  pattern6["color"] = "#800080";
  patterns.add(pattern6);

  JsonObject pattern7 = patterns.createNestedObject();
  pattern7["name"] = "Scanner";
  pattern7["type"] = "scanner";
  pattern7["description"] = "Scanner effect";
  pattern7["color"] = "#FFA500";
  patterns.add(pattern7);

  JsonObject pattern8 = patterns.createNestedObject();
  pattern8["name"] = "Solid Color";
  pattern8["type"] = "solid";
  pattern8["description"] = "Solid color fill";
  pattern8["color"] = "#FFFF00";
  patterns.add(pattern8);

  String response;
  serializeJson(doc, response);
  server.send(200, "application/json", response);
}

String getHTMLHeader() {
  return R"(<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>)" + String(deviceName) + R"(</title>
    <link rel="stylesheet" href="/style.css">
</head>
<body>)";
}

String getHTMLFooter() {
  return R"(</body>
<script src="/script.js"></script>
</html>)";
}

String getControlPanel() {
  String panel = R"(<div class='container'>
    <h1>)" + String(deviceName) + R"(</h1>

    <div class='status-panel'>
        <div class='status-item'>
            <span class='label'>Pattern:</span>
            <span class='value' id='current-pattern'>Rainbow</span>
        </div>
        <div class='status-item'>
            <span class='label'>Speed:</span>
            <span class='value' id='current-speed'>5</span>
        </div>
        <div class='status-item'>
            <span class='label'>Brightness:</span>
            <span class='value' id='current-brightness'>128</span>
        </div>
        <div class='status-item'>
            <span class='label'>LED Count:</span>
            <span class='value'>)" + String(NUM_LEDS) + R"(</span>
        </div>
    </div>

    <div class='control-panel'>
        <h2>Pattern Control</h2>

        <div class='pattern-buttons'>)";

  // Add pattern buttons
  panel += "<button class='pattern-btn active' onclick='setPattern(\"rainbow\")'>Rainbow</button>";
  panel += "<button class='pattern-btn' onclick='setPattern(\"chase\")'>Chase</button>";
  panel += "<button class='pattern-btn' onclick='setPattern(\"fade\")'>Fade</button>";
  panel += "<button class='pattern-btn' onclick='setPattern(\"sparkle\")'>Sparkle</button>";
  panel += "<button class='pattern-btn' onclick='setPattern(\"color_wipe\")'>Color Wipe</button>";
  panel += "<button class='pattern-btn' onclick='setPattern(\"theater_chase\")'>Theater Chase</button>";
  panel += "<button class='pattern-btn' onclick='setPattern(\"scanner\")'>Scanner</button>";
  panel += "<button class='pattern-btn' onclick='setPattern(\"solid\")'>Solid</button>";

  panel += R"(</div>

        <div class='control-sliders'>
            <div class='slider-control'>
                <label for='speed-slider'>Speed: <span id='speed-value'>5</span></label>
                <input type='range' id='speed-slider' min='1' max='10' value='5' class='slider'>
            </div>

            <div class='slider-control'>
                <label for='brightness-slider'>Brightness: <span id='brightness-value'>128</span></label>
                <input type='range' id='brightness-slider' min='0' max='255' value='128' class='slider'>
            </div>
        </div>

        <div class='control-buttons'>
            <button class='control-btn' onclick='toggleAnimation()'>Pause</button>
            <button class='control-btn' onclick='clearStrip()'>Clear</button>
            <button class='control-btn' onclick='randomPattern()'>Random</button>
        </div>
    </div>

    <div class='info-panel'>
        <h3>System Information</h3>
        <div class='info-item'>
            <span class='label'>LED Count:</span>
            <span class='value'>)" + String(NUM_LEDS) + R"(</span>
        </div>
        <div class='info-item'>
            <span class='label'>Color Order:</span>
            <span class='value'>)" + String(COLOR_ORDER) + R"(</span>
        </div>
        <div class='info-item'>
            <span class='label'>Web Control:</span>
            <span class='value'>)" + String(ENABLE_WEB_CONTROL ? "Enabled" : "Disabled") + R"(</span>
        </div>
    </div>
</div>)";

  return panel;
}

String getJavaScript() {
  return R"(let currentPattern = 'rainbow';
let currentSpeed = 5;
let currentBrightness = 128;
let animationRunning = true;

function updateStatus() {
  fetch('/status')
    .then(response => response.json())
    .then(data => {
      currentPattern = data.pattern;
      currentSpeed = data.speed;
      currentBrightness = data.brightness;
      animationRunning = data.animationRunning;

      document.getElementById('current-pattern').textContent = currentPattern.charAt(0).toUpperCase() + currentPattern.slice(1);
      document.getElementById('current-speed').textContent = currentSpeed;
      document.getElementById('current-brightness').textContent = currentBrightness;

      // Update active pattern button
      document.querySelectorAll('.pattern-btn').forEach(btn => {
        btn.classList.remove('active');
        if (btn.textContent.toLowerCase() === currentPattern.toLowerCase()) {
          btn.classList.add('active');
        }
      });

      // Update sliders
      document.getElementById('speed-slider').value = currentSpeed;
      document.getElementById('speed-value').textContent = currentSpeed;
      document.getElementById('brightness-slider').value = currentBrightness;
      document.getElementById('brightness-value').textContent = currentBrightness;
    })
    .catch(error => console.error('Status update error:', error));
}

function setPattern(pattern) {
  fetch('/control', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
    },
    body: 'pattern=' + pattern
  })
  .then(response => response.json())
  .then(data => {
    if (data.success) {
      updateStatus();
    } else {
      console.error('Error setting pattern:', data.error);
    }
  })
  .catch(error => console.error('Pattern control error:', error));
}

function updateControls() {
  const speed = document.getElementById('speed-slider').value;
  const brightness = document.getElementById('brightness-slider').value;

  fetch('/control', {
    method: 'POST',
    headers: {
      'content-type': 'application/x-www-form-urlencoded',
    },
    body: 'speed=' + speed + '&brightness=' + brightness
  })
  .then(response => response.json())
  .then(data => {
    if (data.success) {
      updateStatus();
    }
  })
  .catch(error => console.error('Control update error:', error));
}

function toggleAnimation() {
  animationRunning = !animationRunning;
  const btn = event.target;
  btn.textContent = animationRunning ? 'Pause' : 'Resume';
}

function clearStrip() {
  fetch('/control', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
    },
    body: 'pattern=solid&color=#000000'
  })
  .then(response => response.json())
  .catch(error => console.error('Clear error:', error));
}

function randomPattern() {
  const patterns = ['rainbow', 'chase', 'fade', 'sparkle', 'color_wipe', 'theater_chase', 'scanner', 'solid'];
  const randomIndex = Math.floor(Math.random() * patterns.length);
  setPattern(patterns[randomIndex]);
}

// Event listeners
document.getElementById('speed-slider').addEventListener('input', function(e) {
  document.getElementById('speed-value').textContent = e.target.value;
  updateControls();
});

document.getElementById('brightness-slider').addEventListener('input', function(e) {
  document.getElementById('brightness-value').textContent = e.target.value;
  updateControls();
});

// Auto-update status every 2 seconds
setInterval(updateStatus, 2000);)";
}

String getCSS() {
  return R"(* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
  }

  body {
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    min-height: 100vh;
    color: #333;
  }

  .container {
    max-width: 800px;
    margin: 0 auto;
    padding: 20px;
  }

  h1 {
    text-align: center;
    color: white;
    margin-bottom: 30px;
    text-shadow: 2px 2px 4px rgba(0,0,0,0.3);
  }

  .status-panel {
    background: white;
    border-radius: 15px;
    padding: 20px;
    margin-bottom: 20px;
    box-shadow: 0 8px 32px rgba(0,0,0,0.1);
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
    gap: 15px;
  }

  .status-item {
    display: flex;
    justify-content: space-between;
    align-items: center;
  }

  .label {
    font-weight: 600;
    color: #666;
  }

  .value {
    font-weight: bold;
    color: #333;
    padding: 4px 8px;
    background: #f0f0f0;
    border-radius: 4px;
  }

  .control-panel {
    background: white;
    border-radius: 15px;
    padding: 25px;
    margin-bottom: 20px;
    box-shadow: 0 8px 32px rgba(0,0,0,0.1);
  }

  .control-panel h2 {
    margin-top: 0;
    color: #333;
  }

  .pattern-buttons {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(120px, 1fr));
    gap: 10px;
    margin-bottom: 20px;
  }

  .pattern-btn {
    padding: 12px 16px;
    border: none;
    border-radius: 8px;
    background: #667eea;
    color: white;
    font-weight: bold;
    cursor: pointer;
    transition: all 0.3s ease;
  }

  .pattern-btn:hover {
    background: #5a67d8;
    transform: scale(1.05);
  }

  .pattern-btn.active {
    background: #4CAF50;
  }

  .control-sliders {
    margin-bottom: 20px;
  }

  .slider-control {
    margin-bottom: 15px;
  }

  .slider-control label {
    display: block;
    margin-bottom: 10px;
    font-weight: 600;
    color: #666;
  }

  .slider {
    width: 100%;
    height: 8px;
    border-radius: 4px;
    background: #ddd;
    outline: none;
    -webkit-appearance: none;
  }

  .slider::-webkit-slider-thumb {
    -webkit-appearance: none;
    appearance: none;
    width: 24px;
    height: 24px;
    border-radius: 50%;
    background: #667eea;
    cursor: pointer;
  }

  .slider::-moz-range-thumb {
    width: 24px;
    height: 24px;
    border-radius: 50%;
    background: #667eea;
    cursor: pointer;
    border: none;
  }

  .control-buttons {
    display: flex;
    gap: 10px;
  }

  .control-btn {
    flex: 1;
    padding: 12px 20px;
    border: none;
    border-radius: 8px;
    background: #667eea;
    color: white;
    font-weight: bold;
    cursor: pointer;
    transition: all 0.3s ease;
  }

  .control-btn:hover {
    background: #5a67d8;
    transform: scale(1.05);
  }

  .info-panel {
    background: white;
    border-radius: 15px;
    padding: 20px;
    box-shadow: 0 8px 32px rgba(0,0,0,0.1);
  }

  .info-panel h3 {
    margin-top: 0;
    color: #333;
  }

  .info-item {
    display: flex;
    justify-content: space-between;
    margin-bottom: 10px;
  }
})";
}
#endif
